INSERT INTO `nutrients` VALUES (1,'energy_kcal','kcal',-2.00,'moderate','Calories provide energy to the body. Excessively high calorie intake may contribute to weight gain and obesity.'),(2,'protein_g','g',8.00,'positive','Protein supports muscle growth, repair, satiety, and overall metabolic health.'),(3,'carbohydrates_g','g',1.00,'neutral','Carbohydrates are a primary energy source. Excess refined carbohydrates may negatively affect metabolic health.'),(4,'sugars_g','g',-7.00,'negative','High sugar intake may contribute to obesity, diabetes, insulin resistance, and dental issues.'),(5,'added_sugars_g','g',-9.00,'high_negative','Added sugars provide empty calories and are strongly associated with metabolic diseases and obesity.'),(6,'fat_g','g',1.00,'neutral','Dietary fats are essential for hormones and energy, but excessive intake may increase calorie load.'),(7,'saturated_fat_g','g',-6.00,'negative','High saturated fat intake may increase LDL cholesterol and cardiovascular disease risk.'),(8,'trans_fat_g','g',-10.00,'very_high_negative','Trans fats are strongly linked to heart disease, inflammation, and poor metabolic health.'),(9,'monounsaturated_fat_g','g',6.00,'positive','Monounsaturated fats may support heart health and improve cholesterol balance.'),(10,'polyunsaturated_fat_g','g',7.00,'positive','Polyunsaturated fats, including omega fats, support brain and cardiovascular health.'),(11,'fiber_g','g',9.00,'high_positive','Dietary fiber supports digestion, satiety, blood sugar control, and gut health.'),(12,'sodium_mg','mg',-7.00,'negative','Excess sodium intake may contribute to hypertension and cardiovascular disease.'),(13,'cholesterol_mg','mg',-2.00,'moderate','Dietary cholesterol may affect blood cholesterol in some individuals.'),(14,'calcium_mg','mg',7.00,'positive','Calcium supports bone strength, muscle function, and nerve signaling.'),(15,'iron_mg','mg',7.00,'positive','Iron is essential for oxygen transport and preventing anemia.'),(16,'potassium_mg','mg',8.00,'positive','Potassium helps regulate blood pressure, fluid balance, and muscle function.'),(17,'vitamin_a','mcg',7.00,'positive','Vitamin A supports vision, immunity, and skin health.'),(18,'vitamin_c','mg',8.00,'positive','Vitamin C supports immunity, antioxidant protection, and collagen production.'),(19,'vitamin_d','mcg',8.00,'positive','Vitamin D supports bone health, immunity, and calcium absorption.'),(20,'vitamin_b12','mcg',7.00,'positive','Vitamin B12 supports nerve function, red blood cells, and energy metabolism.'),(21,'caffeine_mg','mg',-1.00,'conditional','Moderate caffeine intake may improve alertness, but excessive intake can cause anxiety and sleep issues.');
/*!40000 ALTER TABLE `nutrients` ENABLE KEYS */;
